// === PRICING ENGINE ===
const getMarkup=(cost,tiers)=>{if(cost<=0)return 1;const t=tiers.find(x=>cost>=x.min&&cost<=x.max);return t?t.m:1.5;};
const fmt=n=>"$"+Number(n).toFixed(2);
const _tl=v=>(v!=null&&!isNaN(v)?v:0).toLocaleString?.()??"0";
const fmtK=n=>n>=1000?"$"+Math.round(n/100)/10+"K":fmt(n);

const calcOptions=(svc,parts,settings)=>{
  const matCost=svc.p?svc.p.reduce((s,comp)=>{if(Array.isArray(comp)){const pt=parts.find(x=>x.i===comp[0]);return s+(pt?pt.c*comp[1]:0);}const pt=parts.find(x=>x.i===comp);return s+(pt?pt.c:0);},0):0;
  const markup=getMarkup(matCost,settings.markupTiers);
  const markedMat=matCost*markup;
  const rate=svc.j==="install"?settings.installRate:settings.serviceRate;
  const labor=svc.h*rate;
  const base=markedMat+labor;
  const loadedCost=matCost+(svc.h*(settings.loadedLaborRate||45));
  const tGP=settings.targetGP||60;
  const cRate=settings.turnover?.commissionRate||0.02;
  const calcTier=(mult)=>{const price=Math.round(base*mult);const gp=price>0?Math.round((price-loadedCost)/price*100):0;return{price,gp,commission:Math.round(price*cRate),belowFloor:gp<tGP};};
  return{
    good:calcTier(settings.goodMult),
    better:calcTier(settings.betterMult),
    best:calcTier(settings.bestMult),
    matCost,labor,base,loadedCost
  };
};


