// === SIGNATURE PAD COMPONENT (module-level to prevent React remounting) ===
const SignaturePad=({onConfirm,onCancel,title,subtitle,accentColor})=>{
  const canvasRef=useRef(null);
  const [isDrawing,setIsDrawing]=useState(false);
  const [hasDrawn,setHasDrawn]=useState(false);
  const [sigName,setSigName]=useState("");
  const lastPos=useRef({x:0,y:0});
  const getPos=(e)=>{
    const canvas=canvasRef.current;if(!canvas)return{x:0,y:0};
    const rect=canvas.getBoundingClientRect();
    const touch=e.touches?e.touches[0]:e;
    return{x:(touch.clientX-rect.left)*(canvas.width/rect.width),y:(touch.clientY-rect.top)*(canvas.height/rect.height)};
  };
  const startDraw=(e)=>{e.preventDefault();setIsDrawing(true);lastPos.current=getPos(e);};
  const draw=(e)=>{
    e.preventDefault();if(!isDrawing)return;
    const ctx=canvasRef.current?.getContext("2d");if(!ctx)return;
    const pos=getPos(e);
    ctx.strokeStyle="#ffffff";ctx.lineWidth=2.5;ctx.lineCap="round";ctx.lineJoin="round";
    ctx.beginPath();ctx.moveTo(lastPos.current.x,lastPos.current.y);ctx.lineTo(pos.x,pos.y);ctx.stroke();
    lastPos.current=pos;setHasDrawn(true);
  };
  const endDraw=()=>setIsDrawing(false);
  const clearSig=()=>{
    const ctx=canvasRef.current?.getContext("2d");if(!ctx)return;
    ctx.clearRect(0,0,canvasRef.current.width,canvasRef.current.height);setHasDrawn(false);
  };
  const confirmSig=()=>{
    if(!sigName?.trim()){alert("Enter customer name");return;}
    if(!hasDrawn){alert("Customer must sign above");return;}
    const dataUrl=canvasRef.current.toDataURL("image/png");
    onConfirm({name:sigName,signature:dataUrl,timestamp:new Date().toISOString()});
  };
  const ac=accentColor||T.gold;
  return(<div style={{position:"fixed",top:0,left:"50%",transform:"translateX(-50%)",width:"100%",maxWidth:isDesk?"none":480,height:"100vh",background:"rgba(0,0,0,0.95)",zIndex:500,display:"flex",flexDirection:"column",padding:20,overflowY:"auto"}} className="su">
    <div style={{textAlign:"center",marginBottom:16}}>
      <div style={{fontSize:24,fontFamily:"'Bebas Neue'",color:ac,letterSpacing:"0.1em"}}>{title||"SIGNATURE REQUIRED"}</div>
      <div style={{fontSize:11,color:T.w50,marginTop:4,lineHeight:1.5}}>{subtitle||"Customer signature below authorizes the described work."}</div>
    </div>
    <div style={{fontSize:11,fontFamily:"'Bebas Neue'",color:T.w60,letterSpacing:"0.12em",marginBottom:6}}>CUSTOMER NAME</div>
    <input value={sigName} onChange={e=>setSigName(e.target.value)} placeholder="Print Full Name"
      style={{width:"100%",padding:14,background:T.card,border:`2px solid ${ac}60`,color:T.w,fontSize:16,textAlign:"center",outline:"none",marginBottom:16,fontFamily:"'Barlow',sans-serif"}}/>
    <div style={{fontSize:11,fontFamily:"'Bebas Neue'",color:T.w60,letterSpacing:"0.12em",marginBottom:6}}>SIGN BELOW</div>
    <div style={{position:"relative",marginBottom:8}}>
      <canvas ref={canvasRef} width={400} height={160}
        style={{width:"100%",height:160,background:T.card,border:`2px solid ${hasDrawn?ac:T.border}`,touchAction:"none",cursor:"crosshair"}}
        onMouseDown={startDraw} onMouseMove={draw} onMouseUp={endDraw} onMouseLeave={endDraw}
        onTouchStart={startDraw} onTouchMove={draw} onTouchEnd={endDraw}/>
      {!hasDrawn&&<div style={{position:"absolute",top:"50%",left:"50%",transform:"translate(-50%,-50%)",color:T.w30,fontSize:12,pointerEvents:"none",fontFamily:"'Barlow',sans-serif"}}>✍️ Draw signature here</div>}
      <div style={{position:"absolute",bottom:8,left:16,right:16,height:1,background:T.w20}}/>
    </div>
    <button onClick={clearSig} style={{alignSelf:"flex-end",padding:"4px 12px",background:"transparent",border:`1px solid ${T.border}`,color:T.w40,fontSize:10,fontWeight:800,cursor:"pointer",marginBottom:16}}>CLEAR</button>
    <div style={{fontSize:8,color:T.w30,textAlign:"center",lineHeight:1.6,marginBottom:16}}>
      By signing above, I acknowledge and agree to the terms described. This electronic signature is legally binding and equivalent to a handwritten signature.
    </div>
    <div style={{display:"flex",gap:8}}>
      <button onClick={onCancel} style={{flex:1,padding:14,background:"transparent",border:`2px solid ${T.border}`,color:T.w50,fontSize:13,fontWeight:800,cursor:"pointer",fontFamily:"'Bebas Neue'",letterSpacing:"0.08em"}}>CANCEL</button>
      <button onClick={confirmSig} style={{flex:2,padding:14,background:`linear-gradient(135deg,${ac},${ac}cc)`,border:"none",color:ac===T.gold||ac===T.green?"#000":T.w,fontSize:16,fontWeight:900,fontFamily:"'Bebas Neue'",letterSpacing:"0.1em",cursor:"pointer",boxShadow:`0 4px 20px ${ac}30`}}>✍️ CONFIRM SIGNATURE</button>
    </div>
  </div>);
};

// ╔══════════════════════════════════════════════════════════════╗
