        return[...prev,{id:"cust-"+Date.now(),name:d.customerName,address:d.address||"",phone:d.customerPhone||"",email:"",personalityType:"",pipeType:"",waterHeater:"",propertyAge:0,sqft:0,memberTier:null,memberSince:"",referralSource:"",lifetimeValue:d.revenue||0,lastVisit:jobRecord.date,notes:"",jobHistory:[jobRecord],equipment:[]}];
