                      return[{l:"PENDING",v:pending,c:pending>0?"#f97316":"#22c55e"},{l:"ESCALATED",v:escalated,c:escalated>0?"#ef4444":"#22c55e"},{l:"TODAY",v:discountRequests.filter(function(r){return r.ts>Date.now()-86400000;})?.length,c:"#3b82f6"}].map(function(s){return <div key={s.l} style={{textAlign:"center",padding:"6px 12px",background:s.c+"10",border:"1px solid "+s.c+"40"}}><div style={{fontSize:7,color:C.gray600,fontWeight:800}}>{s.l}</div><div style={{fontSize:18,fontWeight:900,color:s.c,fontFamily:"Barlow Condensed"}}>{s.v}</div></div>;});
