                  return [
                    <div key={i+"l"} style={{padding:"8px 12px",background:isGP?"rgba(34,197,94,0.08)":"transparent",borderTop:isGP?"2px solid #22c55e":"none"}}>
                      <span style={{fontSize:12,color:isGP?C.white:C.gray400,fontWeight:isGP?900:400,fontFamily:isGP?"Barlow Condensed":"inherit"}}>{l.label}</span>
                    </div>,
                    <div key={i+"v"} style={{padding:"8px 12px",textAlign:"right",background:isGP?"rgba(34,197,94,0.08)":"transparent",borderTop:isGP?"2px solid #22c55e":"none"}}>
                      <span style={{fontSize:isGP?16:13,color:l.color,fontWeight:isGP?900:700,fontFamily:"Barlow Condensed"}}>{l.val}</span>
                    </div>
                  ];
