                    <div key={m.l} style={{textAlign:"center",padding:8,background:m.c+"08",border:`1px solid ${m.c}20`}}>
                      <div style={{fontSize:18,fontFamily:"'Bebas Neue'",color:m.c}}>{m.v}</div>
                      <div style={{fontSize:7,color:T.w50,fontWeight:800,letterSpacing:"0.1em"}}>{m.l}</div>
                    </div>
