                <div key={m.l} style={{padding:6,background:m.c+"08",textAlign:"center"}}><div style={{fontSize:14,fontFamily:"'Bebas Neue'",color:m.c}}>{m.v}</div><div style={{fontSize:7,color:T.w40,fontWeight:800}}>{m.l}</div></div>
