                    var partsCost=0;Object.values(deptRevenue).forEach(function(d){partsCost+=Math.round(d.rev*d.partsCostPct/100);});
                    var gp=totalRev-partsCost;var np=gp-totalLabor-overheadTotal;
                    var techData=techTeam.map(function(t){return t.name+": CB "+t.callbackRate+"%, memb "+t.membershipConversion+"%, rating "+t.avgRating;}).join("; ");
