                    return "Monthly Revenue: $"+totalRev?.toLocaleString?.()??"0"+" ("+revItems.join(", ")+"). Parts Cost: $"+partsCost?.toLocaleString?.()??"0"+". Gross Profit: $"+gp?.toLocaleString?.()??"0"+" ("+Math.round(gp/totalRev*100)+"%). Total Labor: $"+totalLabor?.toLocaleString?.()??"0"+". Overhead: $"+overheadTotal?.toLocaleString?.()??"0"+". Net Profit: $"+np?.toLocaleString?.()??"0"+" ("+Math.round(np/totalRev*100)+"%). Annual projection: $"+(totalRev*12).toLocaleString?.()??"0"+". Staff: "+ownerStaff?.length+" ("+staffLines.join(", ")+"). Techs: "+techData+". Marketing: "+mktData+". Trucks: 3. Labor rates: $345/hr service, $425/hr install.";
