                if(!ch)return{spend:0,leads:0,booked:0,moProfit:0,moROI:0,cpl:0,cpa:0,clvCac:0,ppd:0,bookRate:0,ticket:0,ltROI:0,ch:{name:"",icon:"",color:"#555"}};
