                return{spend:ch.monthlySpend,leads:ch.leadsPerMonth,booked:booked,moProfit:moProfit,moROI:moROI,cpl:cpl,cpa:cpa,clvCac:clvCac,ppd:ppd,bookRate:ch.bookingRate,ticket:ch.avgTicket,ltROI:ltROI,ch:ch};
