                return <button key={t.id} onClick={function(){setAlTab(t.id);}} style={{padding:"8px 16px",fontSize:11,fontWeight:800,cursor:"pointer",fontFamily:"Barlow Condensed",textTransform:"uppercase",letterSpacing:"0.05em",borderRadius:0,background:alTab===t.id?t.c:"transparent",color:alTab===t.id?"#000":t.c,border:"2px solid "+t.c}}>{t.label}</button>;
