      {/* ─── AI JOB SUMMARY GENERATOR ─── */}
      {tab==="jobsummary"&&<div>
        <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:16}}>
          <button onClick={()=>setTab("more")} style={{background:"none",border:"none",color:T.w60,fontSize:18,cursor:"pointer"}}>←</button>
          <div style={{fontFamily:"'Bebas Neue'",fontSize:22,letterSpacing:"0.08em",color:T.cyan}}>📄 AI JOB SUMMARY</div>
        </div>
        <div style={{fontSize:11,color:T.w50,marginBottom:14}}>One tap generates a complete customer-facing job summary from your notes, photos, and selected services.</div>
        <div style={{padding:16,background:`linear-gradient(180deg,#111,${T.cyan}10)`,border:`3px solid ${T.cyan}40`,marginBottom:12}}>
          <div style={{fontSize:10,color:T.cyan,fontWeight:800,letterSpacing:"0.12em",marginBottom:8}}>JOB DETAILS TO INCLUDE:</div>
          <textarea value={jobNotes||"Water heater 14 years old, rust at base, T&P valve dripping, anode rod depleted. Expansion tank missing. Recommended 50-gal replacement with expansion tank."} onChange={e=>setJobNotes(e.target.value)} rows={4} style={{width:"100%",background:"#0a0a0e",border:`1px solid ${T.border}`,color:T.w,fontSize:12,padding:10,resize:"none",outline:"none",lineHeight:1.6}}/>
        </div>
        <button onClick={async()=>{setJobSummaryLoading(true);setJobSummaryText("");try{const r=await fetch("https://api.anthropic.com/v1/messages",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:1000,messages:[{role:"user",content:`You are a professional plumbing/HVAC technician writing a customer-facing job summary. Based on these tech notes, write a clean, professional summary that includes: 1) What was found 2) What was done 3) Recommendations for future 4) Warranty info. Keep it friendly and professional, 3-4 short paragraphs. Tech notes: "${jobNotes||"Water heater inspection - 14 year old unit with rust and dripping T&P valve"}"`}]})});const d=await r.json();setJobSummaryText(d.content[0]?.text||"No response");}catch(e){setJobSummaryText("Summary generation unavailable");}setJobSummaryLoading(false);}} disabled={jobSummaryLoading} style={{width:"100%",padding:16,background:`linear-gradient(135deg,${T.cyan},#0891b2)`,border:"none",color:T.w,fontSize:16,fontFamily:"'Bebas Neue'",letterSpacing:"0.12em",cursor:"pointer",marginBottom:12,opacity:jobSummaryLoading?0.6:1}}>
          {jobSummaryLoading?"📄 GENERATING...":"📄 GENERATE JOB SUMMARY"}
        </button>
        {jobSummaryText&&<div style={{padding:16,background:`linear-gradient(180deg,#111,${T.cyan}08)`,border:`2px solid ${T.cyan}25`,borderLeft:`4px solid ${T.cyan}`}}>
          <div style={{fontSize:9,color:T.cyan,fontWeight:800,letterSpacing:"0.12em",marginBottom:8}}>CUSTOMER-FACING SUMMARY:</div>
          <div style={{fontSize:12,color:T.w80,lineHeight:1.8,whiteSpace:"pre-wrap"}}>{jobSummaryText}</div>
          <div style={{display:"flex",gap:6,marginTop:12}}>
            <button style={{flex:1,padding:10,background:`${T.green}15`,border:`2px solid ${T.green}30`,color:T.green,fontSize:11,fontWeight:800,cursor:"pointer"}}>📱 TEXT TO CUSTOMER</button>
            <button style={{flex:1,padding:10,background:`${T.purple}15`,border:`2px solid ${T.purple}30`,color:T.purple,fontSize:11,fontWeight:800,cursor:"pointer"}}>📧 EMAIL TO CUSTOMER</button>
          </div>
        </div>}
      </div>}

      {/* ─── COST OF WAITING CALCULATOR ─── */}
      {tab==="costcalc"&&<div>
        <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:16}}>
          <button onClick={()=>setTab("more")} style={{background:"none",border:"none",color:T.w60,fontSize:18,cursor:"pointer"}}>←</button>
          <div style={{fontFamily:"'Bebas Neue'",fontSize:22,letterSpacing:"0.08em",color:T.red}}>💸 COST OF WAITING</div>
        </div>
        <div style={{fontSize:11,color:T.w50,marginBottom:14}}>Show the customer what it COSTS them to delay. Fear of loss closes more jobs than features.</div>
        <div style={{display:"flex",gap:4,marginBottom:14,overflowX:"auto"}}>
          {["Water Heater","Furnace","AC System","Sewer Line","Leaking Pipe"].map(s=>(
            <button key={s} onClick={()=>setCostCalcService(s)} style={{padding:"8px 12px",background:costCalcService===s?T.red+"18":"transparent",border:`2px solid ${costCalcService===s?T.red:T.border}`,color:costCalcService===s?T.red:T.w50,fontSize:9,fontWeight:800,whiteSpace:"nowrap",cursor:"pointer"}}>{s}</button>
          ))}
        </div>
        {(()=>{
          const data={
            "Water Heater":{monthly:"$45-85/mo wasted energy",emergency:"$3,000-5,000 emergency replacement",damage:"$5,000-15,000 water damage",insurance:"May void homeowner insurance",total1yr:"$2,500-4,000",total3yr:"$8,000-18,000"},
            "Furnace":{monthly:"$60-120/mo excess gas bills",emergency:"$4,000-8,000 mid-winter emergency",damage:"$0 — but risk of CO poisoning",insurance:"Red-tagged = no insurance coverage",total1yr:"$3,200-5,500",total3yr:"$10,000-22,000"},
            "AC System":{monthly:"$50-100/mo excess electric",emergency:"$4,500-9,000 peak-season install",damage:"Mold from humidity = $3,000-10,000",insurance:"Refrigerant leak = EPA violation",total1yr:"$3,000-6,000",total3yr:"$9,000-20,000"},
            "Sewer Line":{monthly:"$0 — but deteriorating daily",emergency:"$8,000-15,000 emergency excavation",damage:"$10,000-50,000 foundation damage",insurance:"Most policies exclude sewers",total1yr:"$8,000-15,000",total3yr:"$15,000-50,000"},
            "Leaking Pipe":{monthly:"$30-80/mo excess water bills",emergency:"$1,500-4,000 emergency burst repair",damage:"$5,000-25,000 mold/structural",insurance:"Slow leaks often excluded",total1yr:"$2,000-6,000",total3yr:"$6,000-25,000"}
          }[costCalcService];
          return <div>
            <div style={{textAlign:"center",marginBottom:14}}>
              <div style={{fontSize:18,fontFamily:"'Bebas Neue'",color:T.red,textShadow:`0 0 20px ${T.red}30`}}>WHAT HAPPENS IF YOU WAIT?</div>
            </div>
            {[
              {icon:"📊",label:"MONTHLY WASTE",v:data.monthly,c:"#f97316"},
              {icon:"🚨",label:"EMERGENCY COST",v:data.emergency,c:T.red},
              {icon:"🏠",label:"PROPERTY DAMAGE RISK",v:data.damage,c:"#8b5cf6"},
              {icon:"🛡️",label:"INSURANCE IMPACT",v:data.insurance,c:T.cyan}
            ].map(r=>(
              <div key={r.label} style={{display:"flex",alignItems:"center",gap:12,padding:12,background:`linear-gradient(180deg,#111,${r.c}08)`,border:`2px solid ${r.c}25`,borderLeft:`4px solid ${r.c}`,marginBottom:6}}>
                <span style={{fontSize:20}}>{r.icon}</span>
                <div><div style={{fontSize:8,color:r.c,fontWeight:800,letterSpacing:"0.1em"}}>{r.label}</div><div style={{fontSize:13,color:T.w80,fontWeight:700}}>{r.v}</div></div>
              </div>
            ))}
            <div style={{marginTop:14,display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
              <div style={{padding:16,background:`linear-gradient(180deg,#111,${T.red}15)`,border:`3px solid ${T.red}50`,textAlign:"center"}}>
                <div style={{fontSize:8,color:T.red,fontWeight:800,letterSpacing:"0.1em"}}>1-YEAR COST OF WAITING</div>
                <div style={{fontSize:18,fontFamily:"'Bebas Neue'",color:T.red,textShadow:`0 0 15px ${T.red}30`}}>{data.total1yr}</div>
              </div>
              <div style={{padding:16,background:`linear-gradient(180deg,#111,${T.red}20)`,border:`3px solid ${T.red}60`,textAlign:"center"}}>
                <div style={{fontSize:8,color:T.red,fontWeight:800,letterSpacing:"0.1em"}}>3-YEAR COST OF WAITING</div>
                <div style={{fontSize:18,fontFamily:"'Bebas Neue'",color:T.red,textShadow:`0 0 15px ${T.red}30`}}>{data.total3yr}</div>
              </div>
            </div>
            <div style={{marginTop:12,padding:12,background:`${T.green}08`,border:`2px solid ${T.green}20`,textAlign:"center"}}>
              <div style={{fontSize:12,color:T.green,fontWeight:700}}>Fix it today and SAVE {data.total3yr} over 3 years</div>
            </div>
          </div>;
        })()}
      </div>}

      {/* ─── EQUIPMENT AGE SCANNER ─── */}
      {tab==="agescan"&&<div>
        <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:16}}>
          <button onClick={()=>setTab("more")} style={{background:"none",border:"none",color:T.w60,fontSize:18,cursor:"pointer"}}>←</button>
          <div style={{fontFamily:"'Bebas Neue'",fontSize:22,letterSpacing:"0.08em",color:"#f97316"}}>🔎 EQUIPMENT AGE SCANNER</div>
        </div>
        <div style={{fontSize:11,color:T.w50,marginBottom:14}}>Enter the serial number from the data plate. AI decodes the manufacture date and calculates remaining life.</div>
        <div style={{padding:16,background:`linear-gradient(180deg,#111,#f9731610)`,border:`3px solid #f9731640`}}>
          <input value={ageSerial} onChange={e=>setAgeSerial(e.target.value)} placeholder="Enter serial number (e.g. BHW0914A12345)" style={{width:"100%",padding:14,background:"#0a0a0e",border:`2px solid ${T.border}`,color:T.w,fontSize:16,fontFamily:"'Barlow Condensed'",letterSpacing:"0.1em",textAlign:"center",outline:"none",marginBottom:10}}/>
          <button onClick={()=>{if(!ageSerial?.trim())return;const yearCode=ageSerial.match(/(\d{2})(\d{2})/);const yr=yearCode?2000+parseInt(yearCode[1].slice(0,2)):2010;const age=new Date().getFullYear()-yr;setAgeResult({year:yr,age,lifespan:age>12?"PAST EXPECTED LIFE":age>8?"APPROACHING END OF LIFE":"WITHIN USEFUL LIFE",color:age>12?T.red:age>8?T.gold:T.green,remaining:Math.max(0,15-age)});}} style={{width:"100%",padding:14,background:`linear-gradient(135deg,#f97316,#c2410c)`,border:"none",color:T.w,fontSize:14,fontFamily:"'Bebas Neue'",letterSpacing:"0.1em",cursor:"pointer"}}>🔎 DECODE SERIAL NUMBER</button>
        </div>
        {ageResult&&<div style={{marginTop:14}}>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:6,marginBottom:12}}>
            {[{l:"MANUFACTURED",v:ageResult.year.toString(),c:"#3b82f6"},{l:"AGE",v:ageResult.age+" YRS",c:ageResult.color},{l:"REMAINING",v:ageResult.remaining+" YRS",c:ageResult.remaining<=3?T.red:T.green}].map(s=>(
              <div key={s.l} style={{textAlign:"center",padding:10,background:`linear-gradient(180deg,#111,${s.c}15)`,border:`3px solid ${s.c}50`}}>
                <div style={{fontSize:16,fontWeight:900,color:s.c,fontFamily:"'Bebas Neue'"}}>{s.v}</div>
                <div style={{fontSize:6,color:s.c,fontWeight:900,letterSpacing:"0.1em"}}>{s.l}</div>
              </div>
            ))}
          </div>
          <div style={{padding:14,background:`linear-gradient(180deg,#111,${ageResult.color}12)`,border:`3px solid ${ageResult.color}40`,textAlign:"center"}}>
            <div style={{fontSize:20,fontFamily:"'Bebas Neue'",color:ageResult.color}}>{ageResult.lifespan}</div>
            <div style={{fontSize:11,color:T.w60,marginTop:4}}>{ageResult.age>10?"Recommend discussing replacement options with the homeowner.":ageResult.age>6?"Schedule annual maintenance to extend remaining life.":"Equipment is within normal service life."}</div>
          </div>
        </div>}
      </div>}

